import{_ as n,c as a,o as s,a as t}from"./app.71f27b91.js";const e='{"title":"Coupled Components with provide/inject","description":"","frontmatter":{},"headers":[{"level":2,"title":"Alternatives","slug":"alternatives"}],"relativePath":"patterns/coupled-components-with-provide-inject.md","lastUpdated":1642121780083}',o={},p=[t('<h1 id="coupled-components-with-provide-inject" tabindex="-1">Coupled Components with <code>provide</code>/<code>inject</code> <a class="header-anchor" href="#coupled-components-with-provide-inject" aria-hidden="true">#</a></h1><p>There are various ways for components to communicate in Vue. The <code>provide</code>/<code>inject</code> mechanism is one of them, and it&#39;s generally not well understood.</p><p>It&#39;s common to hear <code>provide</code> and <code>inject</code> described as &#39;long-range props&#39; or &#39;dependency injection&#39;. While those can be useful ways to think of them, a major use case is for communication between tightly coupled components.</p><p>The term &#39;coupling&#39; is often used as a criticism of a design, but there are many cases where tightly coupled components make sense. These are cases where a particular component needs to be a child (or deeper descendant) of another, specific component. A few examples:</p><ol><li>An <a href="./../components/accordion.html">accordion</a> is often implemented using a parent container and expandable child panels.</li><li>A <a href="./../components/tabs.html">tabs</a> component may be broken down into several smaller components, e.g. for the tab buttons and the content containers. These all need to communicate to ensure the correct thing is showing at any given time.</li><li>A <a href="./../components/radio-group.html">radio group</a> or checkbox group, for communicating with the radio/checkbox children.</li><li>A map component will need to communicate with marker components.</li><li>A table component may need to communicate with headers, rows and cells.</li></ol><p>While it is often possible for these components to communicate using props and events, that only works if one of the components is directly responsible for creating the other. It doesn&#39;t work if the two components are both created by a common parent.</p><p>Let&#39;s see a quick example:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map</span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>my-map</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>In this scenario <code>my-map</code> and <code>my-map-marker</code> can&#39;t communicate with each other using props and events without the consuming template doing a lot of the work to pass things along.</p><p>This is where <code>provide</code> and <code>inject</code> really shine. They allow <code>my-map</code> to <code>provide</code> values that can then be injected into <code>my-map-marker</code>.</p><p>While values can only be provided down the component tree, passing a function allows communication back up the tree. For example, let&#39;s say we want <code>my-map-marker</code> to be able to register itself with the <code>my-map</code> component. We might implement that like this:</p><div class="language-js"><pre><code><span class="token comment">// my-map.vue</span>\n<span class="token keyword">const</span> <span class="token function-variable function">register</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token comment">/* ... various logic ... */</span>\n  \n  <span class="token keyword">return</span> <span class="token punctuation">{</span> map<span class="token punctuation">,</span> unregister <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n<span class="token function">provide</span><span class="token punctuation">(</span><span class="token string">&#39;register-marker&#39;</span><span class="token punctuation">,</span> register<span class="token punctuation">)</span>\n</code></pre></div><div class="language-js"><pre><code><span class="token comment">// my-map-marker.vue</span>\n<span class="token keyword">const</span> register <span class="token operator">=</span> <span class="token function">inject</span><span class="token punctuation">(</span><span class="token string">&#39;register-marker&#39;</span><span class="token punctuation">)</span>\n\n<span class="token keyword">const</span> <span class="token punctuation">{</span> map<span class="token punctuation">,</span> unregister <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">register</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n\n<span class="token function">onUnmounted</span><span class="token punctuation">(</span>unregister<span class="token punctuation">)</span>\n</code></pre></div><p>The usage pattern here is very similar to using a composable. The <code>register</code> function behaves much like a <code>useX</code> function, returning an object that contains everything the caller might need.</p><p>For more complete examples of this pattern, see the <a href="./../components/accordion.html">accordion</a> and <a href="./../components/tabs.html">tabs</a> components.</p><p>While this registration pattern can be useful, it isn&#39;t the only way to use <code>provide</code> and <code>inject</code> for communicating between tightly coupled components. Data and functions can be passed down to emulate props and events respectively. The <a href="./../components/radio-group.html">Radio Group example</a> does something similar.</p><h2 id="alternatives" tabindex="-1">Alternatives <a class="header-anchor" href="#alternatives" aria-hidden="true">#</a></h2><p>Sometimes it&#39;s possible to implement this type of tight coupling using <code>render</code> functions and direct manipulation of the VNodes. That requires digging into the internals of Vue, which can lead to some unpleasant surprises if you aren&#39;t sure what you&#39;re doing.</p><p>Another alternative is to use scoped slots, though they require the consuming template to get involved.</p><p>For example:</p><div class="language-vue"><pre><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map</span> <span class="token attr-name">v-slot</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>props<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token attr-name">v-bind</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>props<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token attr-name">v-bind</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>props<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>my-map-marker</span> <span class="token attr-name">v-bind</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>props<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>\n  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>my-map</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>The <code>props</code> object is created by the <code>my-map</code> component and is passed to the <code>&lt;slot&gt;</code>. The consuming template shown above then passes that on to each <code>my-map-marker</code> using <code>v-bind</code>.</p><p>For the maps example, this probably isn&#39;t the way to go. The extra hassle in the consuming template isn&#39;t worth it when the components are that tightly coupled. However, scoped slots tend to be preferable in cases where the components are not tightly coupled, allowing the consuming component to decide which components should be tied together.</p>',23)];var c=n(o,[["render",function(n,t,e,o,c,i){return s(),a("div",null,p)}]]);export{e as __pageData,c as default};
